function numberOfIslands(data) {
    if (!data || data.length === 0) return 0;
    const lines = data.split('\n');
    const [rows, cols] = lines[0].split(' ').map(Number);
    const grid = lines.slice(1, rows + 1).map(line => line.split(' ').map(Number));
    let islandCount = 0;

    const dfs = (r, c) => {
        if (r < 0 || r >= rows || c < 0 || c >= cols || grid[r][c] === 0) return;
        grid[r][c] = 0; // mark as visited
        dfs(r + 1, c); // down
        dfs(r - 1, c); // up
        dfs(r, c + 1); // right
        dfs(r, c - 1); // left
    };

    for (let i = 0; i < rows; i++) {
        for (let j = 0; j < cols; j++) {
            if (grid[i][j] === 1) {
                islandCount++;
                dfs(i, j);
            }
        }
    }
    return islandCount;
}

