class Solution {
    public int numberOfIslands(char[][] data) {
        if (data == null || data.length == 0) return 0;
        int count = 0;
        int rows = data.length;
        int cols = data[0].length;
        boolean[][] visited = new boolean[rows][cols];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (data[i][j] == '1' && !visited[i][j]) {
                    dfs(data, visited, i, j, rows, cols);
                    count++;
                }
            }
        }
        return count;
    }
    private void dfs(char[][] data, boolean[][] visited, int i, int j, int rows, int cols) {
        if (i < 0 || i >= rows || j < 0 || j >= cols || data[i][j] == '0' || visited[i][j]) {
            return;
        }
        visited[i][j] = true;
        dfs(data, visited, i + 1, j, rows, cols);
        dfs(data, visited, i - 1, j, rows, cols);
        dfs(data, visited, i, j + 1, rows, cols);
        dfs(data, visited, i, j - 1, rows, cols);
    }
}

