class Solution {
    public int numberOfIslands(char[][] data) {
        if (data == null || data.length == 0) return 0;
        int rows = data.length, cols = data[0].length;
        UnionFind uf = new UnionFind(rows * cols);
        for (int r = 0; r < rows; r++) {
            for (int c = 0; c < cols; c++) {
                if (data[r][c] == '1') {
                    int index = r * cols + c;
                    if (r > 0 && data[r - 1][c] == '1') {
                        uf.union(index, (r - 1) * cols + c);
                    }
                    if (c > 0 && data[r][c - 1] == '1') {
                        uf.union(index, r * cols + (c - 1));
                    }
                }
            }
        }
        return uf.getCount();
    }
    private class UnionFind {
        private int[] parent;
        private int[] rank;
        private int count;
        public UnionFind(int size) {
            parent = new int[size];
            rank = new int[size];
            count = 0;
            for (int i = 0; i < size; i++) {
                parent[i] = i;
                count++;
            }
        }
        public int find(int p) {
            if (parent[p] != p) {
                parent[p] = find(parent[p]);
            }
            return parent[p];
        }
        public void union(int p, int q) {
            int rootP = find(p);
            int rootQ = find(q);
            if (rootP != rootQ) {
                if (rank[rootP] > rank[rootQ]) {
                    parent[rootQ] = rootP;
                }
                else if (rank[rootP] < rank[rootQ]) {
                    parent[rootP] = rootQ;
                }
                else {
                    parent[rootQ] = rootP;
                    rank[rootP]++;
                }
                count--;
            }
        }
        public int getCount() {
            return count;
        }
    }
}

