package main

type UnionFind struct {
    parent []int
    rank   []int
}

func NewUnionFind(size int) *UnionFind {
    parent := make([]int, size)
    rank := make([]int, size)
    for i := range parent {
        parent[i] = i
    }
    return &UnionFind{parent: parent, rank: rank}
}

func (uf *UnionFind) Find(x int) int {
    if uf.parent[x] != x {
        uf.parent[x] = uf.Find(uf.parent[x])
    }
    return uf.parent[x]
}

func (uf *UnionFind) Union(x int, y int) {
    rootX := uf.Find(x)
    rootY := uf.Find(y)
    if rootX != rootY {
        if uf.rank[rootX] > uf.rank[rootY] {
            uf.parent[rootY] = rootX
        } else if uf.rank[rootX] < uf.rank[rootY] {
            uf.parent[rootX] = rootY
        } else {
            uf.parent[rootY] = rootX
            uf.rank[rootX]++
        }
    }
}

func numberOfIslands(data [][]byte) int {
    if len(data) == 0 || len(data[0]) == 0 {
        return 0
    }
    rows, cols := len(data), len(data[0])
    uf := NewUnionFind(rows * cols)
    directions := [][2]int{{1, 0}, {-1, 0}, {0, 1}, {0, -1}}
    islandCount := 0

    for r := 0; r < rows; r++ {
        for c := 0; c < cols; c++ {
            if data[r][c] == '1' {
                islandCount++
                index := r*cols + c
                for _, dir := range directions {
                    newR, newC := r+dir[0], c+dir[1]
                    if newR >= 0 && newR < rows && newC >= 0 && newC < cols && data[newR][newC] == '1' {
                        uf.Union(index, newR*cols+newC)
                    }
                }
            }
        }
    }

    uniqueRoots := make(map[int]struct{})
    for r := 0; r < rows; r++ {
        for c := 0; c < cols; c++ {
            if data[r][c] == '1' {
                root := uf.Find(r*cols + c)
                uniqueRoots[root] = struct{}{}
            }
        }
    }

    return len(uniqueRoots)
}

